151	export function resolveAppModelSelection(
152	  provider: ProviderKind,
153	  customModels: readonly string[],
154	  selectedModel: string | null | undefined,
155	): string {
156	  const options = getAppModelOptions(provider, customModels, selectedModel);
157	  const trimmedSelectedModel = selectedModel?.trim();
158	  if (trimmedSelectedModel) {
159	    const direct = options.find((option) => option.slug === trimmedSelectedModel);
160	    if (direct) {
161	      return direct.slug;
162	    }
163	
164	    const byName = options.find(
165	      (option) => option.name.toLowerCase() === trimmedSelectedModel.toLowerCase(),
166	    );
167	    if (byName) {
168	      return byName.slug;
169	    }
170	  }
171	
172	  const normalizedSelectedModel = normalizeModelSlug(selectedModel, provider);
173	  if (!normalizedSelectedModel) {
174	    return getDefaultModel(provider);
175	  }
176	
177	  return (
178	    options.find((option) => option.slug === normalizedSelectedModel)?.slug ??
179	    getDefaultModel(provider)
180	  );
181	}
182	
183	export function getSlashModelOptions(
184	  provider: ProviderKind,
185	  customModels: readonly string[],
186	  query: string,
187	  selectedModel?: string | null,
188	): AppModelOption[] {
189	  const normalizedQuery = query.trim().toLowerCase();
190	  const options = getAppModelOptions(provider, customModels, selectedModel);
191	  if (!normalizedQuery) {
192	    return options;
193	  }
194	
195	  return options.filter((option) => {
196	    const searchSlug = option.slug.toLowerCase();
197	    const searchName = option.name.toLowerCase();
198	    return searchSlug.includes(normalizedQuery) || searchName.includes(normalizedQuery);
199	  });
200	}
201	
202	function emitChange(): void {
203	  for (const listener of listeners) {
204	    listener();
205	  }
206	}
207	
208	function parsePersistedSettings(value: string | null): AppSettings {
209	  if (!value) {
210	    return DEFAULT_APP_SETTINGS;
211	  }
212	
213	  try {
214	    return normalizeAppSettings(Schema.decodeSync(Schema.fromJsonString(AppSettingsSchema))(value));
215	  } catch {
216	    return DEFAULT_APP_SETTINGS;
217	  }
218	}
219	
220	export function getAppSettingsSnapshot(): AppSettings {
221	  if (typeof window === "undefined") {
222	    return DEFAULT_APP_SETTINGS;
223	  }
224	
225	  const raw = window.localStorage.getItem(APP_SETTINGS_STORAGE_KEY);
226	  if (raw === cachedRawSettings) {
227	    return cachedSnapshot;
228	  }
229	
230	  cachedRawSettings = raw;
231	  cachedSnapshot = parsePersistedSettings(raw);
232	  return cachedSnapshot;
233	}
234	
235	function persistSettings(next: AppSettings): void {
236	  if (typeof window === "undefined") return;
237	
238	  const raw = JSON.stringify(next);
239	  try {
240	    if (raw !== cachedRawSettings) {
241	      window.localStorage.setItem(APP_SETTINGS_STORAGE_KEY, raw);
242	    }
243	  } catch {
244	    // Best-effort persistence only.
245	  }
246	
247	  cachedRawSettings = raw;
248	  cachedSnapshot = next;
249	}
250	
251	function subscribe(listener: () => void): () => void {
252	  listeners.push(listener);
253	
254	  const onStorage = (event: StorageEvent) => {
255	    if (event.key === APP_SETTINGS_STORAGE_KEY) {
256	      emitChange();
257	    }
258	  };
259	
260	  window.addEventListener("storage", onStorage);
261	  return () => {
262	    listeners = listeners.filter((entry) => entry !== listener);
263	    window.removeEventListener("storage", onStorage);
264	  };
265	}
266	
267	export function useAppSettings() {
268	  const settings = useSyncExternalStore(
269	    subscribe,
270	    getAppSettingsSnapshot,
271	    () => DEFAULT_APP_SETTINGS,
272	  );
273	
274	  const updateSettings = useCallback((patch: Partial<AppSettings>) => {
275	    const next = normalizeAppSettings(
276	      Schema.decodeSync(AppSettingsSchema)({
277	        ...getAppSettingsSnapshot(),
278	        ...patch,
279	      }),
280	    );
281	    persistSettings(next);
282	    emitChange();
283	  }, []);
284	
285	  const resetSettings = useCallback(() => {
286	    persistSettings(DEFAULT_APP_SETTINGS);
287	    emitChange();
288	  }, []);
289	
290	  return {
291	    settings,
292	    updateSettings,
293	    resetSettings,
294	    defaults: DEFAULT_APP_SETTINGS,
295	  } as const;
296	}
