import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ color, label }: { color: string; label: string }) {
  return (
    <span
      className="inline-block size-5 rounded-full border border-border"
      style={{ backgroundColor: color }}
      aria-label={label}
    />
  );
}

function ThemeCard({
  theme,
  selected,
  onSelect,
}: {
  theme: Theme;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-start justify-between gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onSelect}
    >
      <span className="flex flex-col gap-1.5">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="flex items-center gap-1.5">
          <ThemeSwatch color={theme.colors.background} label={`${theme.name} background`} />
          <ThemeSwatch color={theme.colors.foreground} label={`${theme.name} foreground`} />
          <ThemeSwatch color={theme.colors.accent} label={`${theme.name} accent`} />
          <ThemeSwatch color={theme.colors.sidebar} label={`${theme.name} sidebar`} />
        </span>
      </span>
      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

export function ThemeSelector() {
  const { themeId, setThemeById, setTheme, theme: preference, availableThemes } = useTheme();
  const isSystem = preference === "system";

  return (
    <div className="space-y-3">
      <div className="space-y-2" role="radiogroup" aria-label="Theme">
        {availableThemes.map((t) => (
          <ThemeCard
            key={t.id}
            theme={t}
            selected={!isSystem && themeId === t.id}
            onSelect={() => setThemeById(t.id)}
          />
        ))}

        {/* System (auto) option */}
        <button
          type="button"
          role="radio"
          aria-checked={isSystem}
          className={`flex w-full items-start justify-between gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
            isSystem
              ? "border-primary/60 bg-primary/8 text-foreground"
              : "border-border bg-background text-muted-foreground hover:bg-accent"
          }`}
          onClick={() => setTheme("system")}
        >
          <span className="flex flex-col">
            <span className="text-sm font-medium">System</span>
            <span className="text-xs">Automatically match your OS appearance setting.</span>
          </span>
          {isSystem ? (
            <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
              Active
            </span>
          ) : null}
        </button>
      </div>
    </div>
  );
}

