/** Light or dark classification for a theme. */
export type ThemeAppearance = "light" | "dark";

export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly appearance: ThemeAppearance;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: string;
  /**
   * CSS variable overrides applied to `:root` when this theme is active.
   * Keys are variable names **without** the leading `--`.
   * Empty for themes that rely on the stylesheet defaults (t3-light, t3-dark).
   */
  readonly cssVariables: Readonly<Record<string, string>>;
}

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';
const DEFAULT_FONT_SIZE = "16px";

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    appearance: "dark",
    colors: {
      background: "#0c0c0d",
      foreground: "#f5f5f5",
      accent: "#6d8aff",
      sidebar: "#111113",
      editor: "#0c0c0d",
      terminal: "#0c0c0d",
      statusBar: "#111113",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
    cssVariables: {},
  },
  {
    id: "t3-light",
    name: "T3 Light",
    appearance: "light",
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "#3b5bdb",
      sidebar: "#ffffff",
      editor: "#ffffff",
      terminal: "#ffffff",
      statusBar: "#ffffff",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
    cssVariables: {},
  },
  {
    id: "t3-midnight",
    name: "Midnight",
    appearance: "dark",
    colors: {
      background: "#0a0e17",
      foreground: "#d4dae5",
      accent: "#7b93ff",
      sidebar: "#0f1420",
      editor: "#0a0e17",
      terminal: "#080c14",
      statusBar: "#0f1420",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
    cssVariables: {
      background: "#0a0e17",
      foreground: "#d4dae5",
      card: "#0f1420",
      "card-foreground": "#d4dae5",
      popover: "#0f1420",
      "popover-foreground": "#d4dae5",
      primary: "oklch(0.65 0.2 260)",
      "primary-foreground": "#ffffff",
      secondary: "rgba(255,255,255,0.04)",
      "secondary-foreground": "#d4dae5",
      muted: "rgba(255,255,255,0.04)",
      "muted-foreground": "#6b7a94",
      accent: "rgba(255,255,255,0.06)",
      "accent-foreground": "#d4dae5",
      destructive: "#e05a5a",
      "destructive-foreground": "#f87171",
      border: "rgba(255,255,255,0.06)",
      input: "rgba(255,255,255,0.08)",
      ring: "oklch(0.65 0.2 260)",
      info: "#60a5fa",
      "info-foreground": "#93bbfd",
      success: "#34d399",
      "success-foreground": "#6ee7b7",
      warning: "#fbbf24",
      "warning-foreground": "#fcd34d",
    },
  },
] as const;

const THEME_MAP = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

/** Return all available themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/** Look up a theme by id. Returns `undefined` when not found. */
export function getTheme(id: string): Theme | undefined {
  return THEME_MAP.get(id);
}

/** The default theme id used when no preference is stored. */
export function getDefaultThemeId(): string {
  return "t3-dark";
}

