import { useCallback, useEffect, useMemo, useSyncExternalStore } from "react";
import {
  getTheme,
  listThemes,
  type Theme,
  type ThemeAppearance,
} from "@t3tools/shared/themes";

type ThemePreference = "light" | "dark" | "system";
type ThemeSnapshot = {
  preference: ThemePreference;
  themeId: string;
  systemDark: boolean;
};

const PREFERENCE_KEY = "t3code:theme";
const THEME_ID_KEY = "t3code:theme-id";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Module-level external store
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

/** Set of CSS variable names we last applied inline so we can clean them up. */
let appliedCssVarKeys: string[] = [];

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

// ---------------------------------------------------------------------------
// Storage helpers
// ---------------------------------------------------------------------------

function getStoredPreference(): ThemePreference {
  const raw = localStorage.getItem(PREFERENCE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(THEME_ID_KEY);
  if (raw && getTheme(raw)) return raw;
  return "";
}

/**
 * Resolve the effective theme id from the stored preference and explicit id.
 * When no explicit theme id is stored we derive one from the preference.
 */
function resolveThemeId(preference: ThemePreference, storedId: string): string {
  if (storedId) return storedId;

  if (preference === "light") return "t3-light";
  if (preference === "dark") return "t3-dark";
  // "system" — pick based on OS
  return getSystemDark() ? "t3-dark" : "t3-light";
}

/**
 * Derive the legacy preference value from a named theme so the two storage
 * keys stay in sync and callers that only read `preference` still work.
 */
function preferenceForTheme(theme: Theme): ThemePreference {
  return theme.appearance;
}

// ---------------------------------------------------------------------------
// CSS application
// ---------------------------------------------------------------------------

function clearThemeCssVariables() {
  const style = document.documentElement.style;
  for (const key of appliedCssVarKeys) {
    style.removeProperty(`--${key}`);
  }
  appliedCssVarKeys = [];
}

function applyThemeCssVariables(theme: Theme) {
  clearThemeCssVariables();

  const entries = Object.entries(theme.cssVariables);
  for (const [key, value] of entries) {
    document.documentElement.style.setProperty(`--${key}`, value);
  }
  appliedCssVarKeys = entries.map(([key]) => key);

  // Font overrides — only set when they differ from the defaults so the CSS
  // fallback chain in index.css can take over for built-in themes.
  if (theme.fontFamily) {
    document.documentElement.style.setProperty("--theme-font-family", theme.fontFamily);
    appliedCssVarKeys.push("theme-font-family");
  }
  if (theme.fontSize) {
    document.documentElement.style.setProperty("--theme-font-size", theme.fontSize);
    appliedCssVarKeys.push("theme-font-size");
  }
}

function applyTheme(themeId: string, appearance: ThemeAppearance, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  document.documentElement.classList.toggle("dark", appearance === "dark");

  const theme = getTheme(themeId);
  if (theme) {
    applyThemeCssVariables(theme);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Apply immediately on module load to prevent flash
// ---------------------------------------------------------------------------

{
  const pref = getStoredPreference();
  const id = resolveThemeId(pref, getStoredThemeId());
  const theme = getTheme(id);
  const appearance: ThemeAppearance = theme
    ? theme.appearance
    : pref === "system"
      ? getSystemDark()
        ? "dark"
        : "light"
      : pref === "dark"
        ? "dark"
        : "light";
  applyTheme(id, appearance);
}

// ---------------------------------------------------------------------------
// Snapshot (useSyncExternalStore)
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const preference = getStoredPreference();
  const storedId = getStoredThemeId();
  const themeId = resolveThemeId(preference, storedId);
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    const pref = getStoredPreference();
    if (pref === "system") {
      const id = resolveThemeId("system", "");
      const theme = getTheme(id);
      applyTheme(id, theme?.appearance ?? (getSystemDark() ? "dark" : "light"), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === PREFERENCE_KEY || e.key === THEME_ID_KEY) {
      const pref = getStoredPreference();
      const id = resolveThemeId(pref, getStoredThemeId());
      const theme = getTheme(id);
      applyTheme(
        id,
        theme?.appearance ?? (pref === "dark" || (pref === "system" && getSystemDark()) ? "dark" : "light"),
        true,
      );
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference, themeId, systemDark } = snapshot;

  const theme = getTheme(themeId);
  const resolvedTheme: "light" | "dark" = theme
    ? theme.appearance
    : preference === "system"
      ? systemDark
        ? "dark"
        : "light"
      : preference === "dark"
        ? "dark"
        : "light";

  const availableThemes = useMemo(() => listThemes(), []);

  /** Legacy setter — accepts "light" | "dark" | "system". */
  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(PREFERENCE_KEY, next);

    // When using the legacy setter, clear the explicit theme id so the
    // preference drives resolution (system/light/dark).
    localStorage.removeItem(THEME_ID_KEY);

    const id = resolveThemeId(next, "");
    const resolved = getTheme(id);
    const appearance: ThemeAppearance = resolved
      ? resolved.appearance
      : next === "dark" || (next === "system" && getSystemDark())
        ? "dark"
        : "light";

    applyTheme(id, appearance, true);
    emitChange();
  }, []);

  /** Select a named theme by id. */
  const setThemeById = useCallback((id: string) => {
    const selected = getTheme(id);
    if (!selected) return;

    localStorage.setItem(THEME_ID_KEY, id);
    localStorage.setItem(PREFERENCE_KEY, preferenceForTheme(selected));

    applyTheme(id, selected.appearance, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount / when snapshot changes
  useEffect(() => {
    const id = resolveThemeId(preference, getStoredThemeId());
    const t = getTheme(id);
    applyTheme(
      id,
      t?.appearance ?? (preference === "dark" || (preference === "system" && getSystemDark()) ? "dark" : "light"),
    );
  }, [preference, themeId]);

  return {
    /** Legacy preference value: "light" | "dark" | "system". */
    theme: preference,
    /** Legacy setter for "light" | "dark" | "system". */
    setTheme,
    /** Resolved to "light" or "dark" — safe for syntax-highlighting / diff libs. */
    resolvedTheme,
    /** The active named theme id (e.g. "t3-dark", "t3-midnight"). */
    themeId,
    /** Select a named theme by id. */
    setThemeById,
    /** All themes available for selection. */
    availableThemes,
  } as const;
}

